#include <stdio.h>
#include <signal.h>
typedef struct { int num; const char *name; const char *action; } SigInfo;
int main(void) {
    SigInfo signals[] = {
        {SIGHUP,  "SIGHUP",  "TERM"},
        {SIGINT,  "SIGINT",  "TERM"},
        {SIGQUIT, "SIGQUIT", "CORE"},
        {SIGILL,  "SIGILL",  "CORE"},
        {SIGSEGV, "SIGSEGV", "CORE"},
        {SIGTERM, "SIGTERM", "TERM"},
        {SIGKILL, "SIGKILL", "TERM (unkillable)"},
        {SIGSTOP, "SIGSTOP", "STOP (unstoppable)"},
        {SIGCHLD, "SIGCHLD", "IGN"},
    };
    printf("%-4s %-10s %s\n", "NUM", "NAME", "DEFAULT");
    for (int i = 0; i < 9; i++)
        printf("%-4d %-10s %s\n", signals[i].num, signals[i].name, signals[i].action);
    return 0;
}

