typedef struct { int num; const char *name; const char *action; } SigInfo;

// ★ Stage 0 — Exemple complet
int main(void) {
    SigInfo signals[] = {
        {SIGHUP,  "SIGHUP",  "TERM"},            // ★ 1 = HangUp
        {SIGINT,  "SIGINT",  "TERM"},             // ★ 2 = Ctrl+C
        {SIGQUIT, "SIGQUIT", "CORE"},             // ★ 3 = Ctrl+\
        {SIGILL,  "SIGILL",  "CORE"},             // ★ 4 = instruction illégale
        {SIGSEGV, "SIGSEGV", "CORE"},             // ★ 11 = segfault
        {SIGTERM, "SIGTERM", "TERM"},             // ★ 15 = terminaison douce
        {SIGKILL, "SIGKILL", "TERM (unkillable)"},// ★ 9 = non interceptable
        {SIGSTOP, "SIGSTOP", "STOP (unstoppable)"},// ★ 19 = non interceptable
        {SIGCHLD, "SIGCHLD", "IGN"},              // ★ 17 = enfant terminé
    };
    printf("%-4s %-10s %s\n", "NUM", "NAME", "DEFAULT");
    for (int i = 0; i < 9; i++)
        printf("%-4d %-10s %s\n", signals[i].num, signals[i].name, signals[i].action);
    return 0;
}

